## Анализ результатов
- Расчет оптимальных уровней запасов для каждой категории
- Анализ чувствительности к изменению спроса
- Визуализация:
  - Гистограммы распределения результатов
  - Графики сходимости оптимизационного алгоритма
  - Дерево категорий с цветовой кодировкой эффективности

## Тестирование
```python
import unittest

class TestPharmacyOptimization(unittest.TestCase):
    def test_experiment_setup(self):
        experiment = PharmacyOptimizationExperiment()
        experiment.setup_parameters(
            distribution_type="normal",
            size=1000,
            mean=100,
            std=15,
            iterations=500
        )
        self.assertEqual(experiment.parameters['distribution_type'], "normal")

    def test_data_generation(self):
        generator = DataGenerator()
        data = generator.generate("normal", 1000, {'mean': 100, 'std': 15})
        self.assertEqual(len(data), 1000)

    def test_optimization_run(self):
        experiment = PharmacyOptimizationExperiment()
        experiment.setup_parameters(iterations=100)
        results = experiment.run()
        self.assertIn('statistics', results)
        self.assertIn('visualizations', results)

if __name__ == '__main__':
    unittest.main()
```

